firmware_template.source:
#include "telegram_bot.h"
#include <WiFi.h>
#include <WiFiClientSecure.h>
#include <UniversalTelegramBot.h>
static WiFiClientSecure _sc;
static UniversalTelegramBot*_bot=nullptr;
static telegram_cb _cb=nullptr;
static unsigned long _l=0;
void telegram_setup(const char*tok){_sc.setCACert(TELEGRAM_CERTIFICATE_ROOT);_bot=new UniversalTelegramBot(tok,_sc);Serial.println("[telegram] OK");}
void telegram_loop(){if(millis()-_l<2000||!_bot)return;_l=millis();int n=_bot->getUpdates(_bot->last_message_received+1);for(int i=0;i<n;i++){if(_cb)_cb(_bot->messages[i].chat_id.c_str(),_bot->messages[i].text.c_str());}}
void telegram_send(const char*id,const char*msg){if(_bot)_bot->sendMessage(id,msg,"");}
void telegram_on_message(telegram_cb cb){_cb=cb;}
